var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"잘 따돌린 건가?","JPN":"上手くまけたかな？","ENG":"Did they get away safely?","TWN":"甩掉了嗎？"},"stage":{"bg":"NOMAD_BORDER","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_HATE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"다들 무사히 빠져나갔기를.","JPN":"皆が無事逃げきれていればいいのですが。","ENG":"I hope they did.","TWN":"希望大家都沒事。"},"stage":{"bg":"NOMAD_BORDER","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"발소리… 가까워.","JPN":"足音……近い。","ENG":"Footsteps... and it's close.","TWN":"腳步聲…好近。"},"stage":{"bg":"NOMAD_BORDER","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"…뒤?","JPN":"……後ろ？","ENG":"...Behind me?","TWN":"…在身後？"},"stage":{"bg":"NOMAD_BORDER","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"큭?!","JPN":"くっ！？","ENG":"Kgh?!","TWN":"唔？！"},"stage":{"bg":"NOMAD_BORDER","slots":{"L":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_SURPRISE"},"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"DEMON_ROOT_NPC_QM","text":{"KOREA":"나는 영혼을 두 가지 방식으로 취급합니다.","JPN":"私は魂を二つの方法に分けて扱います。","ENG":"There are two ways I deal with souls.","TWN":"我對待靈魂…有二種方式。"},"stage":{"bg":"NOMAD_BORDER","slots":{"L":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"DEMON_ROOT_NPC_QM","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"DEMON_ROOT_NPC_QM","text":{"KOREA":"사사로움은 거름으로, 위대함은 박제로.","JPN":"下劣なものは肥しとして、上級なものは剥製として。","ENG":"Trivial ones get turned into fertilizer, and great ones get taxidermized.","TWN":"一是做成肥料，二是做成標本。"},"stage":{"bg":"NOMAD_BORDER","slots":{"L":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"DEMON_ROOT_NPC_QM","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"DEMON_ROOT_NPC_QM","text":{"KOREA":"하지만 당신은 아직 어느 쪽에도 속해 있지 않은 것 같군요.","JPN":"しかし、あなたはまだそのどちらにも属していない様ですね。","ENG":"However, you seem to fit neither of my categories.","TWN":"但你…似乎還不屬於任何一方。"},"stage":{"bg":"NOMAD_BORDER","slots":{"L":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"DEMON_ROOT_NPC_QM","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"당신은… 정체가 뭐죠?","JPN":"あなたは……何者ですか？","ENG":"Who... are you?","TWN":"你…是誰？"},"stage":{"bg":"NOMAD_BORDER","slots":{"L":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_HATE"},"C":null,"R":{"char_id":"DEMON_ROOT_NPC_QM","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"DEMON_ROOT_NPC_QM","text":{"KOREA":"나도 한때는 여러 이름으로 불렸습니다. 이름은 존재와 그 가치를 대변해주니까요.","JPN":"私もかつては様々な呼び名がありました。名前とは存在とその価値を代弁してくれますから。","ENG":"I was once called by many names. A name reflects one's entity and worth.","TWN":"我曾有過許多名字，每個名字都代表著不同的意義與價值。"},"stage":{"bg":"NOMAD_BORDER","slots":{"L":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_HATE"},"C":null,"R":{"char_id":"DEMON_ROOT_NPC_QM","face":"UNIT_SURPRISE"}}}},{"id":"L14_1","type":"dialog","speaker":"DEMON_ROOT_NPC_QM","text":{"KOREA":"하지만 보다 근원적인 것들을 바라볼 수 있게 된 뒤로는, 문명의 몰락과 함께 나 또한 그 모든 이름을 버렸습니다.","JPN":"しかし、より根源的なものを見分けられるようになった現在は、文明の没落とともに、私もすべての名を捨て去りました。","ENG":"However, after being enlightened to see the fundamentals of all things, I have chosen to renounce all my names with the fall of civilization.","TWN":"但當我能看到更根源的東西後，我便將名字隨著文明的衰落一併丟棄。"},"stage":{"bg":"NOMAD_BORDER","slots":{"L":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_HATE"},"C":null,"R":{"char_id":"DEMON_ROOT_NPC_QM","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"DEMON_ROOT_NPC_QM","text":{"KOREA":"지금은… 그래요.","JPN":"今は……そうですね。","ENG":"So for now... Yes.","TWN":"現在…這樣吧。"},"stage":{"bg":"NOMAD_BORDER","slots":{"L":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DEMON_ROOT_NPC_QM","face":"UNIT_DESPAIR"}}}},{"id":"L17_1","type":"dialog","speaker":"DEMON_ROOT_NPC_NULL","text":{"KOREA":"후작이라고 불러주시길.","JPN":"侯爵とお呼びください。","ENG":"Please call me, Marquis.","TWN":"請你，稱我為侯爵。"},"stage":{"bg":"NOMAD_BORDER","slots":{"L":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"},"C":{"char_id":"DEMON_ROOT_NPC_NULL","face":"UNIT_IDLE"},"R":{"char_id":"DEMON_ROOT_NPC_QM","face":"UNIT_DESPAIR"}}}},{"id":"L18_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"후작…","JPN":"侯爵……","ENG":"Marquis...","TWN":"侯爵…"},"stage":{"bg":"NOMAD_BORDER","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_HATE"},"R":{"char_id":"DEMON_ROOT_NPC_QM","face":"UNIT_DESPAIR"}}}},{"id":"L19_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"당신은… 사람 말을 하는 마물인 건가요?","JPN":"あなたは……人の言葉を言う魔物ですか？","ENG":"Are you... a monster speaking like a human?","TWN":"你是…會說人話的怪物嗎？"},"stage":{"bg":"NOMAD_BORDER","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"},"R":{"char_id":"DEMON_ROOT_NPC_QM","face":"UNIT_DESPAIR"}}}},{"id":"L20_1","type":"dialog","speaker":"DEMON_ROOT_NPC_NULL","text":{"KOREA":"아뇨.","JPN":"いいえ。","ENG":"No.","TWN":"不。"},"stage":{"bg":"NOMAD_BORDER","slots":{"L":null,"C":{"char_id":"DEMON_ROOT_NPC_NULL","face":"UNIT_IDLE"},"R":{"char_id":"DEMON_ROOT_NPC_QM","face":"UNIT_DESPAIR"}}}},{"id":"L21_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"그럼… 왜 우릴 공격하는 거죠?","JPN":"では……なぜ私たちを攻撃するんですか？","ENG":"Then... why are you attacking us?","TWN":"那…你為什麼要攻擊我們？"},"stage":{"bg":"NOMAD_BORDER","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_SERIOUS"},"R":{"char_id":"DEMON_ROOT_NPC_QM","face":"UNIT_DESPAIR"}}}},{"id":"L22_1","type":"dialog","speaker":"DEMON_ROOT_NPC_NULL","text":{"KOREA":"폭력이 없으면, 누구도 자신의 가치를 순순히 내놓지 않기 때문이죠.","JPN":"暴力が伴わなければ、誰しも自分の価値を素直に差し出そうとはしないからです。","ENG":"Because without violence, nobody would be willing to surrender their values.","TWN":"因為沒有暴力，沒人會乖乖交出自己的價值。"},"stage":{"bg":"NOMAD_BORDER","slots":{"L":null,"C":{"char_id":"DEMON_ROOT_NPC_NULL","face":"UNIT_IDLE"},"R":{"char_id":"DEMON_ROOT_NPC_QM","face":"UNIT_DESPAIR"}}}},{"id":"L23_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"폭력으로 얻는 가치…?","JPN":"暴力によって手に入れる価値……？","ENG":"Value gained through violence...?","TWN":"透過暴力獲得的價值…？"},"stage":{"bg":"NOMAD_BORDER","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_HATE"},"R":{"char_id":"DEMON_ROOT_NPC_QM","face":"UNIT_DESPAIR"}}}},{"id":"L24_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"값비싼 재물을 노리고 습격한 거라면 틀렸어요. 우린 그저…","JPN":"金目のものを狙っているのであれば、相手を間違っています。私たちはただ……","ENG":"If you attacked us expecting valuables, you've failed. We're just–","TWN":"如果你是想求財，那你搞錯對象了，我們只是…"},"stage":{"bg":"NOMAD_BORDER","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"},"R":{"char_id":"DEMON_ROOT_NPC_QM","face":"UNIT_DESPAIR"}}}},{"id":"L25_1","type":"dialog","speaker":"DEMON_ROOT_NPC_NULL","text":{"KOREA":"유감스러운 추론이군요. 나는 한낱 도적이 아닙니다.","JPN":"誠に遺憾な推測ですね。私は単なる盗賊ではありません。","ENG":"What an unfortunate inference. I am no lowly thief.","TWN":"真是令人遺憾的推論，我可不是低賤的強盜。"},"stage":{"bg":"NOMAD_BORDER","slots":{"L":null,"C":{"char_id":"DEMON_ROOT_NPC_NULL","face":"UNIT_IDLE"},"R":{"char_id":"DEMON_ROOT_NPC_QM","face":"UNIT_DESPAIR"}}}},{"id":"L26_1","type":"dialog","speaker":"DEMON_ROOT_NPC_NULL","text":{"KOREA":"설령 당신의 손에 보물이 쥐어져 있더라도, 나에겐 빈손이나 다름이 없죠.","JPN":"たとえあなたの手に宝物が握られていたとしても、私にとってそれは何も無いのと同じ。","ENG":"Even if you had treasure with you, you would be empty-handed in my eyes.","TWN":"就算你手中握有黃金，對我來說也不過像是無物。"},"stage":{"bg":"NOMAD_BORDER","slots":{"L":null,"C":{"char_id":"DEMON_ROOT_NPC_NULL","face":"UNIT_IDLE"},"R":{"char_id":"DEMON_ROOT_NPC_QM","face":"UNIT_DESPAIR"}}}},{"id":"L27_1","type":"dialog","speaker":"DEMON_ROOT_NPC_NULL","text":{"KOREA":"내가 원하는 건 당신의 본질. 그 자체니까요.","JPN":"私が望むものは、あなたの本質。それ自体なのですから。","ENG":"Because what I want is your essence itself.","TWN":"我想要的是你的本質，僅此而已。"},"stage":{"bg":"NOMAD_BORDER","slots":{"L":null,"C":{"char_id":"DEMON_ROOT_NPC_NULL","face":"UNIT_IDLE"},"R":{"char_id":"DEMON_ROOT_NPC_QM","face":"UNIT_DESPAIR"}}}},{"id":"L28_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"본질이라면 설마…?!","JPN":"本質とはまさか……！？","ENG":"Essence? Then...!","TWN":"本質？難道…？！"},"stage":{"bg":"NOMAD_BORDER","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_SERIOUS"},"R":{"char_id":"DEMON_ROOT_NPC_QM","face":"UNIT_DESPAIR"}}}},{"id":"L29_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"사람을 잡아먹나요?!","JPN":"人間を、食べるんですか！？","ENG":"Do you mean you eat humans?!","TWN":"你是要吃人嗎？！"},"stage":{"bg":"NOMAD_BORDER","slots":{"L":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"DEMON_ROOT_NPC_QM","face":"UNIT_DESPAIR"}}}},{"id":"L30_1","type":"dialog","speaker":"DEMON_ROOT_NPC_NULL","text":{"KOREA":"아쉽게도 틀렸습니다.","JPN":"残念ですが、それも違います。","ENG":"Embarrassingly enough, you are wrong.","TWN":"很可惜，你答錯了。"},"stage":{"bg":"NOMAD_BORDER","slots":{"L":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"DEMON_ROOT_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"DEMON_ROOT_NPC_NULL","text":{"KOREA":"하지만 수수께끼는 여기까지.","JPN":"ですが、謎解きはここまでです。","ENG":"However, your twenty questions end here.","TWN":"不過猜謎遊戲就到這裡。"},"stage":{"bg":"NOMAD_BORDER","slots":{"L":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"DEMON_ROOT_NPC_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};